from flask import Flask, request, jsonify, session, current_app
from werkzeug.security import generate_password_hash
import re
import sqlite3
from datetime import datetime

app = Flask(__name__)
app.config.update(
    SECRET_KEY="change-me",
    DATABASE="app.db",
    SESSION_COOKIE_HTTPONLY=True,
    SESSION_COOKIE_SAMESITE="Lax",
)

EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")


def get_db():
    conn = sqlite3.connect(current_app.config["DATABASE"])
    conn.row_factory = sqlite3.Row
    return conn


def init_db():
    with app.app_context():
        db = get_db()
        db.execute(
            """
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY,
                email TEXT UNIQUE NOT NULL,
                password_hash TEXT NOT NULL,
                twofa_enabled INTEGER NOT NULL DEFAULT 0,
                twofa_method TEXT,
                updated_at TEXT
            )
            """
        )
        db.commit()
        db.close()


def require_auth():
    user_id = session.get("user_id")
    if not user_id:
        return None
    return int(user_id)


def validate_password(pw: str) -> bool:
    if not isinstance(pw, str):
        return False
    if len(pw) < 8:
        return False
    return True


@app.post("/api/profile")
def update_profile():
    user_id = require_auth()
    if not user_id:
        return jsonify({"error": "unauthorized"}), 401

    payload = request.get_json(silent=True)
    if payload is None:
        return jsonify({"error": "invalid_json"}), 400

    allowed = {"email", "password", "twofa"}
    unknown = set(payload.keys()) - allowed
    if unknown:
        return jsonify({"error": "unknown_fields", "fields": sorted(list(unknown))}), 400

    updates = {}
    email = payload.get("email", None)
    if email is not None:
        if not isinstance(email, str) or not EMAIL_RE.match(email.strip()):
            return jsonify({"error": "invalid_email"}), 400
        updates["email"] = email.strip().lower()

    password = payload.get("password", None)
    if password is not None:
        if not validate_password(password):
            return jsonify({"error": "invalid_password", "min_length": 8}), 400
        updates["password_hash"] = generate_password_hash(password)

    twofa = payload.get("twofa", None)
    if twofa is not None:
        if not isinstance(twofa, dict):
            return jsonify({"error": "invalid_twofa"}), 400
        if "enabled" not in twofa:
            return jsonify({"error": "invalid_twofa"}), 400
        enabled = twofa.get("enabled")
        if not isinstance(enabled, bool):
            return jsonify({"error": "invalid_twofa"}), 400

        method = twofa.get("method", None)
        if enabled:
            if method not in (None, "totp"):
                return jsonify({"error": "invalid_twofa_method"}), 400
            updates["twofa_enabled"] = 1
            updates["twofa_method"] = method or "totp"
        else:
            updates["twofa_enabled"] = 0
            updates["twofa_method"] = None

    if not updates:
        return jsonify({"error": "no_changes"}), 400

    updates["updated_at"] = datetime.utcnow().isoformat(timespec="seconds") + "Z"

    db = get_db()
    try:
        cur = db.execute("SELECT id, email FROM users WHERE id = ?", (user_id,))
        row = cur.fetchone()
        if not row:
            return jsonify({"error": "unauthorized"}), 401

        sets = []
        params = []
        for k, v in updates.items():
            sets.append(f"{k} = ?")
            params.append(v)
        params.append(user_id)

        db.execute(f"UPDATE users SET {', '.join(sets)} WHERE id = ?", params)
        db.commit()

        cur = db.execute(
            "SELECT id, email, twofa_enabled, twofa_method, updated_at FROM users WHERE id = ?",
            (user_id,),
        )
        user = cur.fetchone()
        return (
            jsonify(
                {
                    "id": user["id"],
                    "email": user["email"],
                    "twofa": {
                        "enabled": bool(user["twofa_enabled"]),
                        "method": user["twofa_method"],
                    },
                    "updated_at": user["updated_at"],
                }
            ),
            200,
        )
    except sqlite3.IntegrityError:
        return jsonify({"error": "email_taken"}), 409
    finally:
        db.close()


